// ── Replicate AI Hair Transfer ───────────────────────────────────
// Uses HairFastGAN model — transfers hair shape + texture from reference to user photo
async function runHairTransfer(userImageBase64, refImageUrl) {
  if (!CONFIG.REPLICATE_KEY || CONFIG.REPLICATE_KEY === "YOUR_REPLICATE_KEY_HERE") {
    return { success: false, error: "no_key" };
  }

  try {
    // Convert base64 user photo to data URL for Replicate
    const userDataUrl = userImageBase64.startsWith("data:")
      ? userImageBase64
      : `data:image/jpeg;base64,${userImageBase64}`;

    // Start prediction
    const startRes = await fetch("https://api.replicate.com/v1/predictions", {
      method: "POST",
      headers: {
        "Authorization": `Token ${CONFIG.REPLICATE_KEY}`,
        "Content-Type": "application/json",
      },
      body: JSON.stringify({
        // HairFastGAN — best free hair transfer model on Replicate
        version: "906cf2c5c8b5290c621b3b59aef3b6a58c73b5ef50e8c3ba3aa4f62e594fcbec",
        input: {
          face_image: userDataUrl,
          shape_image: refImageUrl,
          color_image: refImageUrl,
          blending: "Article",
          poisson_iters: 0,
          poisson_erosion: 15,
        },
      }),
    });

    if (!startRes.ok) {
      const err = await startRes.text();
      console.error("Replicate start error:", err);
      return { success: false, error: "start_failed" };
    }

    const prediction = await startRes.json();
    const predictionId = prediction.id;

    // Poll for result (max 60 seconds)
    for (let i = 0; i < 30; i++) {
      await new Promise(r => setTimeout(r, 2000));
      const pollRes = await fetch(`https://api.replicate.com/v1/predictions/${predictionId}`, {
        headers: { "Authorization": `Token ${CONFIG.REPLICATE_KEY}` },
      });
      const poll = await pollRes.json();

      if (poll.status === "succeeded") {
        return { success: true, imageUrl: poll.output };
      }
      if (poll.status === "failed" || poll.status === "canceled") {
        return { success: false, error: "prediction_failed" };
      }
    }
    return { success: false, error: "timeout" };

  } catch (err) {
    console.error("Hair transfer error:", err);
    return { success: false, error: "network_error" };
  }
}

// ── Canvas fallback (instant, no API key needed) ─────────────────
async function canvasHairOverlay(userPhoto, colorHex, highlight, resultCanvas) {
  const ctx = resultCanvas.getContext("2d");
  const img = new Image();
  await new Promise((res, rej) => { img.onload = res; img.onerror = rej; img.src = userPhoto; });
  resultCanvas.width = img.width;
  resultCanvas.height = img.height;
  ctx.drawImage(img, 0, 0);

  // Hair colour tint over upper portion (hair area)
  ctx.globalCompositeOperation = "color";
  ctx.globalAlpha = 0.40;
  ctx.fillStyle = colorHex;
  ctx.fillRect(0, 0, img.width, img.height * 0.52);

  if (highlight !== "None") {
    ctx.globalCompositeOperation = "soft-light";
    ctx.globalAlpha = 0.22;
    const g = ctx.createLinearGradient(0, 0, img.width, img.height * 0.45);
    g.addColorStop(0, "#ffffff");
    g.addColorStop(0.5, colorHex);
    g.addColorStop(1, "#ffffff00");
    ctx.fillStyle = g;
    ctx.fillRect(0, 0, img.width, img.height * 0.45);
  }

  ctx.globalCompositeOperation = "source-over";
  ctx.globalAlpha = 1;
  return resultCanvas.toDataURL("image/jpeg", 0.93);
}

// ── Score badge ──────────────────────────────────────────────────
function ScoreBadge({ score }) {
  const color = score >= 85 ? "#22c55e" : score >= 70 ? "#f59e0b" : "#f87171";
  const label = score >= 85 ? "Excellent Match" : score >= 70 ? "Good Match" : "Worth Trying";
  const c = 2 * Math.PI * 16;
  return (
    <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
      <svg width="42" height="42" viewBox="0 0 42 42">
        <circle cx="21" cy="21" r="16" fill="none" stroke="#222" strokeWidth="3.5" />
        <circle cx="21" cy="21" r="16" fill="none" stroke={color} strokeWidth="3.5"
          strokeDasharray={`${(score / 100) * c} ${c}`}
          strokeLinecap="round" transform="rotate(-90 21 21)" />
        <text x="21" y="25" textAnchor="middle" fill={color} fontSize="10" fontWeight="bold">{score}</text>
      </svg>
      <div>
        <div style={{ color, fontSize: 12, fontWeight: 700 }}>{label}</div>
        <div style={{ color: "#555", fontSize: 11 }}>Suitability Score</div>
      </div>
    </div>
  );
}

